#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const src = path.join(__dirname, '..', 'SKILL.md');
const dst = path.join(__dirname, '..', 'hooks', 'skill-content.js');

const raw = fs.readFileSync(src, 'utf8');
const body = raw.replace(/^---[\s\S]*?---\s*/, '').trim();
const escaped = body
  .replace(/\\/g, '\\\\')
  .replace(/`/g, '\\`')
  .replace(/\$\{/g, '\\${');

const out = [
  '// AUTO-GENERATED by scripts/embed-skill.js. Do not edit by hand.',
  '// Source of truth: ../SKILL.md',
  'module.exports = `' + escaped + '\\n`;',
  '',
].join('\n');

fs.writeFileSync(dst, out);
console.log('wrote', dst, '(' + escaped.length + ' chars)');
